import { Link } from "react-router-dom";
import styled from "styled-components";
import { PlayArrow } from "@material-ui/icons";
import imdb from "../img/imdb.png";
import rotten from "../img/rotten.png";
import { useState } from "react";
import slugify from "slugify";

const Movies = ({ movie }) => {
  const [showw, setShow] = useState(0);

  const showInfo = () => {
    setShow(1);
  };

  const hideInfo = () => {
    setShow(0);
  };

  return (
    <StyledMovies onMouseOver={showInfo} onMouseOut={hideInfo}>
      <Poster>
        <Image>
          <img src={movie.poster} alt="" />
        </Image>
        <Information show={showw}>
          <Title>
            <h2>{movie.title}</h2>
          </Title>
          <Year>
            <h5>Year: {movie.year}</h5>
          </Year>
          <Category>
            <h5>CATEGORY</h5>
            {movie.category.map((category) => (
              <Categories key={category}>
                <Link to={"category/" + category.toLowerCase()}>
                  {category}
                </Link>
              </Categories>
            ))}
          </Category>

          <Score>
            <Imdb>
              <img src={imdb} alt="imdb" />
              <span>{movie.imdb}/10</span>
            </Imdb>
            <div className="hr"></div>
            <Rotten>
              <img src={rotten} alt="rotten" />
              <span>{movie.rotten}%</span>
            </Rotten>
          </Score>
          <Play>
            <Link to={movie.trailerUrl}>
              <h4>Watch Trailer</h4>
            </Link>
            <Link
              to={`watch/${slugify(movie.title, {
                replacement: "-",
                remove: undefined,
                lower: true,
                strict: false,
                locale: "vi",
              })}`}
            >
              <button>
                <PlayArrow />
                Play Now
              </button>
            </Link>
          </Play>
        </Information>
      </Poster>
    </StyledMovies>
  );
};

const Information = styled.div`
  width: 82%;
  height: 99%;
  padding: 0vw 1vw;
  position: absolute;
  left: 0;
  top: 0;
  background-color: rgba(0, 0, 0, 0.6);
  opacity: ${(props) => props.show};
  transition: all 0.5s ease-in-out;
`;

const StyledMovies = styled.div`
  color: white;
  width: 25%;
  margin-bottom: 1vw;
  font-size: 1vw;
`;

const Image = styled.div`
  height: 30vw;
  width: 20vw;
  img {
    width: 20vw;
  }
`;

const Poster = styled.div`
  position: relative;
`;

const Categories = styled.span`
  padding-right: 1.5rem;
`;

const Title = styled.div`
  font-size: 1.4vw;
`;
const Year = styled.div`
  h5 {
    font-size: 1vw;
  }
`;
const Category = styled.div`
  h5 {
    font-size: 1vw;
    margin-bottom: 0.2vw;
  }
`;
const Play = styled.div`
  margin-top: 5vw;
  text-align: center;
  button {
    padding: 0.5vw;
    font-size: 1vw;
    display: flex;
    align-items: center;
    justify-content: center;
    width: 80%;
    height: 4vw;
    margin: auto;
  }
  h4 {
    text-decoration: underline;
  }
`;
const Score = styled.div`
  margin-top: 3vw;
  display: flex;
  align-items: center;
  justify-content: space-between;
  .hr {
    border-left: 2px solid #999999;
    height: 30px;
  }
`;
const Imdb = styled.div`
  font-size: 1.5vw;
  img {
    width: 3vw;
    margin-right: 0.5vw;
  }
`;
const Rotten = styled.div`
  font-size: 1.5vw;
  img {
    width: 4vw;
    margin-right: 0.5vw;
  }
`;

export default Movies;
