import styled from "styled-components";
import { Link, NavLink, Switch } from "react-router-dom";
import logo from "../img/logo.png";

const Header = () => {
  return (
    <StyledHeader>
      <Logo>
        <Link to="/">
          <img src={logo} alt="logo" />
        </Link>
      </Logo>
      <Nav>
        <ul>
          <li>
            <NavLink to="/" exact activeStyle={{ background: "red" }}>
              HOME
            </NavLink>
          </li>
          <li>
            <NavLink to="/movies" activeStyle={{ background: "red" }}>
              BROWSE MOVIE
            </NavLink>
          </li>
          <li>
            <NavLink to="/trending" activeStyle={{ background: "red" }}>
              TRENDING
            </NavLink>
          </li>
          <li>
            <NavLink to="/suggestions" activeStyle={{ background: "red" }}>
              SUGGESTIONS
            </NavLink>
          </li>
          <li>
            <NavLink to="/bookmarks" activeStyle={{ background: "red" }}>
              BOOKMARKS
            </NavLink>
          </li>
        </ul>
      </Nav>
    </StyledHeader>
  );
};

const StyledHeader = styled.header`
  color: white;
  height: 10vh;
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin: 0rem 4vw;
  a {
    text-decoration: none;
    color: inherit;
  }
`;

const Logo = styled.div`
  img {
    width: 10rem;
  }
`;

const Nav = styled.nav`
  ul {
    display: flex;
    list-style: none;
  }
  li {
    a {
      padding: 1vw 2vw;
    }
  }
`;

export default Header;
