import styled from "styled-components";
import data from "../data";
import Movies from "./Movies";

const Content = () => {
  const movies = data();
  return (
    <div>
      <div>
        <Flex>
          {movies.map((movie) => (
            <Movies key={movie.id} movie={movie} />
          ))}
        </Flex>
      </div>
    </div>
  );
};

const Flex = styled.div`
  display: flex;
  justify-content: space-between;
  flex-wrap: wrap;
  align-items: center;
  margin: 0rem 5vw;
`;

export default Content;
