import { createGlobalStyle } from "styled-components";

const GlobalStyle = createGlobalStyle`
  body {
    margin: 0;
    padding: 0;
    background: #1D1D1D;
    font-family: Open-Sans, Helvetica, Sans-Serif;
  }

  button {
    background-color: #6AC045;
    color: white;
    border: none;
    border-radius: 4px;
    font-weight: bold;
    outline: none;
    cursor: pointer;
  }

  a{
    color: inherit;
    text-decoration: none;
  }
`;

export default GlobalStyle;
