import data from "../data";
import { useState, useEffect } from "react";
import slugify from "slugify";
import styled from "styled-components";
import { Link } from "react-router-dom";

const Watch = ({ match }) => {
  const [movieData, setMovieData] = useState(data());
  const [movie, setMovie] = useState(null);

  useEffect(() => {
    const currentMovie = movieData.filter(
      (stateMovie) =>
        slugify(stateMovie.title, {
          replacement: "-",
          remove: undefined,
          lower: true,
          strict: false,
          locale: "vi",
        }) === match.params.slug
    );
    setMovie(currentMovie[0]);
  }, [movieData, match.params.id]);
  return (
    <div>
      {movie && (
        <Container>
          <Top>
            <h1>{movie.title}</h1>
            <h2>
              IMDb <span>{movie.imdb}</span>
            </h2>
          </Top>
          <Information>
            <Poster>
              <img src={movie.poster} alt="poster" />
              <Link to={movie.trailerUrl}>
                <button>Watch Trailer</button>
              </Link>
            </Poster>
            <Description>
              <Desc>
                <p>
                  Possum, başrollerini Sean Harris ve Alun Armstrong'un
                  paylaştığı, Matthew Holness tarafından yazılan ve yönetilen
                  bir 2018 İngiliz psikolojik korku filmi. Film, ufaklığında
                  yaşadığı taciz ve dramayla yüzleşmek zorunda kalan, küçük bir
                  çocuk kuklacısını konu ediniyor. Holness, başkarakter olarak
                  yazdığı, yönettiği ve oynadığı Garth Marenghi'nin, Darkplace
                  adlı televizyon dizisinde çalıştı; ayrıca birkaç kısa öykü
                  yayınladı. Film, korku antolojisi The New Uncanny: Tales of
                  Unease'de yayınlanan Holness'in kısa öyküsü "Possum" un bir
                  uyarlaması. Belirsiz bir skandal yüzünden utanç duyan Philip,
                  çantasını alır ve memleketi Marshwood'a giden bir trene biner.
                  Full HD 1080p kalitede sizlerle olacak olan Possum filminde,
                  Philip tuhaf bir şekilde trende çizim yapan genç bir çocuğa
                  denk gelir ve Philip istenmeden "ne çiziyordun" diye sormak
                  için kenara çekildiğinde, çocuk ona ters bakar ve gider.
                  Philip büyüdüğü eve gelir. Girmeyeceği belirli bir oda vardır.
                  Sarı ve turuncu balonları sarmak için duvar kağıdından siyah
                  duman sızar. Philip cevap vermeyen Maurice adında bir adamı
                  yüksek sesle sorar. Çantasını dışarıdaki bir varile
                  götürdükten ve kuklasını içine doldurduktan sonra Philip, uzun
                  süredir devam eden bir rekabeti yeniler gibi başıboş bir
                  tilkiye bakar. "Possum" sergilerinin tuhaf tarzı budur. Bu,
                  şifreli karakterizasyonlardan, yorumlayıcı çıkarımlardan ve
                  ardışık olmayan ara yollardan, Philip'in çatlak zihnindeki
                  halkın bir parçası olabilecek veya olmayabilecek sembolik
                  manzaralara kadar biçimlendirilmiş ürkütücü bir ruh hali
                  parçasıdır. Geldiği evde yer yer yırtık pırtık ve pistir. Yine
                  de ev boş değildir. Philip’in korkunç amcası Maurice ikamet
                  etmektedir. En önemlisi, Maurice eski bir kuklacıdır ve
                  kuklacılıktaki bazı becerilerini parlayan yeğenine aktarmış
                  gibi görünüyor. Ve Philip'in çantasındaki şey, bu türden bir
                  yaratım gibi görünüyor. Philip geldikten kısa bir süre sonra,
                  yerel basında 14 yaşındaki bir çocuğun ortadan kaybolduğu
                  haberleri yer alır. Maurice, Philip'in bununla bir ilgisi olup
                  olmadığını merak eder. Philip çantasındaki şeyin bununla bir
                  ilgisi olup olmadığını merak edecektir ve gizemin çözülmesi
                  gerekir. Hd film izleme ve 4k film izleme keyfini kesintisiz
                  bir şekilde yaşayacağınız Possum filmi Dublaj ve Altyazı
                  olarak İki dil seçeneğiyle sizlerle.
                </p>
              </Desc>
              <Info>
                <h5>
                  Producer: &nbsp; <span>{movie.producer}</span>
                </h5>
                <h5>
                  Year: &nbsp;<span>{movie.year}</span>
                </h5>
                <h5>
                  Stars: &nbsp;
                  <span>
                    Alun Armstrong, Andy Blithe, Sean Harris, Simon Bubb
                  </span>
                </h5>
                <h5>
                  Category: &nbsp;
                  <span>Dram Filmleri, Gerilim Filmleri, Korku Filmleri</span>
                </h5>
                <h5>
                  Producer: <span>{movie.producer}</span>
                </h5>
              </Info>
            </Description>
          </Information>
          <Video>
            <iframe
              width="100%"
              height="600"
              src="https://www.youtube.com/embed/ow3fhDtRHiU"
              frameborder="0"
              allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
            ></iframe>
          </Video>
        </Container>
      )}
    </div>
  );
};

const Container = styled.div`
  color: white;
  padding: 2vw;
  border-radius: 5px;
  margin: 6vw 15vw;
  background-color: rgba(255, 255, 255, 0.1);
`;

const Top = styled.div`
  display: flex;
  justify-content: space-between;
  h2 {
    color: white;
    text-align: center;
    padding: 5px;
    border-radius: 5px;
    width: 10rem;
    background-color: #dead1f;
    span {
      margin-left: 0.8vw;
      color: rgba(0, 0, 0, 0.7);
    }
  }
`;

const Information = styled.div`
  margin-top: 2vw;
  display: flex;
`;
const Poster = styled.div`
  img {
    border-radius: 5px;
    width: 80%;
    margin-bottom: 1vw;
  }
  button {
    padding: 0.5vw;
    font-size: 1.5vw;
    width: 80%;
    height: 4vw;
    margin: auto;
  }
`;
const Description = styled.div``;
const Desc = styled.div`
  background-color: rgba(61, 61, 61, 1);
  padding: 1vw;
  border-radius: 5px;
  width: 35vw;
  height: 21vw;
  overflow: auto;
  ::-webkit-scrollbar {
    width: 10px;
    background-color: grey;
  }
  ::-webkit-scrollbar-track {
    box-shadow: inset 0 0 6px rgba(0, 0, 0, 0.3);
  }
  ::-webkit-scrollbar-thumb {
    background-color: darkgrey;
    outline: 1px solid slategrey;
    border-radius: 5px;
  }
`;
const Info = styled.div``;

const Video = styled.div`
  margin-top: 5vw;
`;

export default Watch;
